    # ══════════════════════════════════════════════════════════
    #  COMPUTER SCIENCE COURSES
    # ══════════════════════════════════════════════════════════
    {"id": "cs141", "text": "CS 141 Introduction to Computer Science I. Credits: 4. Prerequisites: none. Description: Fundamental programming concepts using Python. Topics include variables, loops, functions, recursion, and basic data structures. Required for all CS and Data Science majors. Offered every fall and spring.", "metadata": {"category": "course", "dept": "CS", "level": "100"}},
    {"id": "cs142", "text": "CS 142 Introduction to Computer Science II. Credits: 3. Prerequisites: CS 141. Description: Object-oriented programming, inheritance, polymorphism, exception handling, file I/O, and introduction to algorithms. Required for CS majors.", "metadata": {"category": "course", "dept": "CS", "level": "100"}},
    {"id": "cs242", "text": "CS 242 Advanced Programming. Credits: 3. Prerequisites: CS 142. Description: Advanced programming techniques including data abstraction, generic programming, GUI development, and software engineering principles.", "metadata": {"category": "course", "dept": "CS", "level": "200"}},
    {"id": "cs344", "text": "CS 344 Algorithms and Data Structures. Credits: 3. Prerequisites: CS 142, MA 211. Description: Design and analysis of algorithms. Topics include sorting, searching, graph algorithms, dynamic programming, greedy algorithms, and computational complexity. Required for CS and Data Science majors.", "metadata": {"category": "course", "dept": "CS", "level": "300"}},
    {"id": "cs348", "text": "CS 348 Computer Organization. Credits: 3. Prerequisites: CS 242. Description: Digital logic, computer arithmetic, memory hierarchy, instruction set architectures, pipelining, and input/output systems.", "metadata": {"category": "course", "dept": "CS", "level": "300"}},
    {"id": "cs443", "text": "CS 443 Database Systems. Credits: 3. Prerequisites: CS 344. Description: Relational database design, SQL, normalization, transactions, concurrency control, and NoSQL databases. Highly recommended for Data Science and Software Engineering tracks.", "metadata": {"category": "course", "dept": "CS", "level": "400"}},
    {"id": "cs444", "text": "CS 444 Operating Systems. Credits: 3. Prerequisites: CS 348. Description: Processes, threads, synchronization, deadlocks, memory management, file systems, and distributed systems fundamentals.", "metadata": {"category": "course", "dept": "CS", "level": "400"}},
    {"id": "cs447", "text": "CS 447 Machine Learning. Credits: 3. Prerequisites: CS 344, STAT 282 or STAT 383. Description: Supervised and unsupervised learning, regression, classification, neural networks, support vector machines, and model evaluation. Highly recommended for Data Science and AI career tracks.", "metadata": {"category": "course", "dept": "CS", "level": "400"}},
    {"id": "cs451", "text": "CS 451 Computer Networks. Credits: 3. Prerequisites: CS 444. Description: Network architecture, protocols (TCP/IP, HTTP, DNS), socket programming, security fundamentals, and wireless networks.", "metadata": {"category": "course", "dept": "CS", "level": "400"}},
    {"id": "cs499", "text": "CS 499 Professional Experience. Credits: 3. Prerequisites: junior standing, 60+ credits completed. Description: Internship, co-op, or directed research related to the student's professional goals. Required for graduation in all CS and Data Science programs. Must be approved by the department.", "metadata": {"category": "course", "dept": "CS", "level": "400"}},
    {"id": "cs541", "text": "CS 541 Computer Algorithms (Graduate). Credits: 3. Prerequisites: Graduate standing or permission. Description: Advanced algorithm design and analysis. Required foundation course for the MS in Computer Science. Must be taken in first semester.", "metadata": {"category": "course", "dept": "CS", "level": "500"}},
    {"id": "cs547", "text": "CS 547 Machine Learning I (Graduate). Credits: 3. Prerequisites: CS 541 or permission. Description: Statistical learning theory, kernel methods, deep learning fundamentals, reinforcement learning basics. Part of the AI/ML graduate track.", "metadata": {"category": "course", "dept": "CS", "level": "500"}},

    # ══════════════════════════════════════════════════════════
    #  MATHEMATICS COURSES
    # ══════════════════════════════════════════════════════════
    {"id": "ma131", "text": "MA 131 Calculus I. Credits: 3. Prerequisites: precalculus or placement. Description: Limits, derivatives, applications of differentiation, introduction to integration. Required for all engineering, CS, math, and science majors. Offered every semester.", "metadata": {"category": "course", "dept": "MA", "level": "100"}},
    {"id": "ma132", "text": "MA 132 Calculus II. Credits: 3. Prerequisites: MA 131. Description: Integration techniques, sequences and series, polar coordinates, parametric equations. Required for engineering, CS, and science majors.", "metadata": {"category": "course", "dept": "MA", "level": "100"}},
    {"id": "ma211", "text": "MA 211 Foundations of Mathematics. Credits: 3. Prerequisites: MA 131. Description: Logic, set theory, proof techniques, relations, functions, and combinatorics. Required for CS majors. Develops mathematical maturity for upper-division coursework.", "metadata": {"category": "course", "dept": "MA", "level": "200"}},
    {"id": "ma231", "text": "MA 231 Differential Equations. Credits: 3. Prerequisites: MA 132. Description: First and higher-order ODEs, systems of equations, Laplace transforms, and introduction to partial differential equations. Required for all engineering majors.", "metadata": {"category": "course", "dept": "MA", "level": "200"}},
    {"id": "ma232", "text": "MA 232 Calculus III. Credits: 3. Prerequisites: MA 132. Description: Multivariable calculus, partial derivatives, multiple integrals, line and surface integrals, vector calculus (Green's, Stokes', and Divergence theorems).", "metadata": {"category": "course", "dept": "MA", "level": "200"}},
    {"id": "ma335", "text": "MA 335 Linear Algebra. Credits: 3. Prerequisites: MA 132. Description: Vectors, matrices, linear transformations, eigenvalues and eigenvectors, orthogonality, and applications. Recommended for CS and Data Science majors interested in ML and AI.", "metadata": {"category": "course", "dept": "MA", "level": "300"}},

    # ══════════════════════════════════════════════════════════
    #  STATISTICS COURSES
    # ══════════════════════════════════════════════════════════
    {"id": "stat282", "text": "STAT 282 Probability and Statistics for Engineers and Scientists. Credits: 3. Prerequisites: MA 132. Description: Probability theory, random variables, distributions, hypothesis testing, regression, and ANOVA. Required for Data Science, CS, and all engineering majors. This course is the prerequisite for CS 447 Machine Learning.", "metadata": {"category": "course", "dept": "STAT", "level": "200"}},
    {"id": "stat383", "text": "STAT 383 Applied Statistics. Credits: 3. Prerequisites: STAT 282. Description: Multiple regression, experimental design, time series analysis, nonparametric methods, and statistical computing with R. Core course for Data Science majors.", "metadata": {"category": "course", "dept": "STAT", "level": "300"}},

    # ══════════════════════════════════════════════════════════
    #  ENGINEERING COURSES
    # ══════════════════════════════════════════════════════════
    {"id": "me221", "text": "ME 221 Statics. Credits: 3. Prerequisites: MA 131, PH 131. Description: Equilibrium of particles and rigid bodies, distributed forces, centroids, moments of inertia, friction, and analysis of trusses and frames. Required for all Mechanical and Aerospace Engineering majors.", "metadata": {"category": "course", "dept": "ME", "level": "200"}},
    {"id": "me323", "text": "ME 323 Thermodynamics I. Credits: 3. Prerequisites: MA 132, PH 131. Description: First and second laws of thermodynamics, thermodynamic properties, power and refrigeration cycles. Required for Mechanical and Aerospace Engineering.", "metadata": {"category": "course", "dept": "ME", "level": "300"}},
    {"id": "che211", "text": "CHE 211 Material and Energy Balances. Credits: 3. Prerequisites: CM 131, MA 131. Description: Systematic application of conservation laws to chemical processes. Includes steady-state and unsteady-state balances with and without chemical reaction. Required first course for Chemical Engineering majors.", "metadata": {"category": "course", "dept": "CHE", "level": "200"}},
    {"id": "ce322", "text": "CE 322 Structural Analysis. Credits: 3. Prerequisites: CE 221 or ES 220. Description: Analysis of statically determinate and indeterminate structures including beams, frames, and trusses. Required for Civil Engineering majors.", "metadata": {"category": "course", "dept": "CE", "level": "300"}},

    # ══════════════════════════════════════════════════════════
    #  BUSINESS COURSES
    # ══════════════════════════════════════════════════════════
    {"id": "sb113", "text": "SB 113 Entrepreneurship and Business Innovation. Credits: 3. Prerequisites: none. Description: Introduction to entrepreneurship, business model development, innovation processes, and lean startup methodology. REQUIRED for ALL undergraduate students in the Reh School of Business regardless of major. Typically taken in freshman year.", "metadata": {"category": "course", "dept": "SB", "level": "100"}},
    {"id": "ac201", "text": "AC 201 Financial Accounting. Credits: 3. Prerequisites: none. Description: Principles of financial accounting, financial statements, recording transactions, assets, liabilities, equity, and cash flows. Required for all Reh School undergraduate programs.", "metadata": {"category": "course", "dept": "AC", "level": "200"}},
    {"id": "fi301", "text": "FI 301 Financial Management. Credits: 3. Prerequisites: AC 201, EC 200. Description: Time value of money, capital budgeting, risk and return, cost of capital, capital structure, and dividend policy. Required for Business Administration and Financial Information & Analysis majors.", "metadata": {"category": "course", "dept": "FI", "level": "300"}},
    {"id": "mk301", "text": "MK 301 Marketing Management. Credits: 3. Prerequisites: SB 113 or AC 201. Description: Marketing strategy, consumer behavior, market segmentation, pricing, promotion, and distribution. Core course for Business Administration majors.", "metadata": {"category": "course", "dept": "MK", "level": "300"}},

    # ══════════════════════════════════════════════════════════
